// Routes:
// /watch/, /stream/, /dl/  → proxy to Koyeb stream server
// ?link=XXX                → show beautiful landing page with GET FILE button
//                            clicking GET FILE opens Telegram → ServeBot → sends file

const KOYEB_URL = "https://marvellous-ilse-dengerous53-077d6f54.koyeb.app";

// Cache serve bot username — refreshes every 5 minutes
let cachedServeBotUsername = null;
let cacheTime = 0;
const CACHE_TTL = 5 * 60 * 1000;


// ── Fetch helpers ──────────────────────────────────────────────────────────────

async function getServeBotUsername() {
  const now = Date.now();
    if (cachedServeBotUsername && (now - cacheTime) < CACHE_TTL) {
        return cachedServeBotUsername;
          }
            try {
                const resp = await fetch(`${KOYEB_URL}/serve_bot`);
                    const data = await resp.json();
                        cachedServeBotUsername = data.username;
                            cacheTime = now;
                                return cachedServeBotUsername;
                                  } catch (err) {
                                      return cachedServeBotUsername || "";
                                        }
                                        }


