                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                // ── Main handler ───────────────────────────────────────────────────────────────

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                addEventListener('fetch', event => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  event.respondWith(handleRequest(event.request));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  async function handleRequest(request) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const url = new URL(request.url);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const pathname = url.pathname;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // ── Stream/Download proxy routes ──────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const streamRoutes = ["/watch/", "/stream/", "/dl/"];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const isStreamRoute = streamRoutes.some(path => pathname.startsWith(path));

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (isStreamRoute) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const targetUrl = KOYEB_URL + pathname + url.search;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const forwardHeaders = new Headers(request.headers);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          forwardHeaders.set("Host", new URL(KOYEB_URL).host);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const koyebResponse = await fetch(targetUrl, {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            method: request.method,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    headers: forwardHeaders,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            body: request.method !== "GET" && request.method !== "HEAD" ? request.body : undefined,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    redirect: "follow",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const responseHeaders = new Headers(koyebResponse.headers);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      responseHeaders.delete("transfer-encoding");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            responseHeaders.delete("connection");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  responseHeaders.set("Access-Control-Allow-Origin", "*");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        responseHeaders.set("Access-Control-Allow-Headers", "Range, Content-Type");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              responseHeaders.set("Access-Control-Expose-Headers", "Content-Range, Content-Length, Accept-Ranges");

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return new Response(koyebResponse.body, {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            status: koyebResponse.status,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    statusText: koyebResponse.statusText,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            headers: responseHeaders,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      } catch (err) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            return new Response("Gateway error: " + err.message, { status: 502 });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // ── File link — show landing page ─────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const linkParam = url.searchParams.get("link");

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (linkParam) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const serveBotUsername = await getServeBotUsername();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (!serveBotUsername) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      return new Response("Service unavailable — serve bot not configured.", { status: 503 });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              // Build Telegram deep link → opens ServeBot → serves file
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const telegramUrl = `https://t.me/${serveBotUsername}?start=${linkParam}`;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      // Show landing page — user clicks GET FILE to open Telegram
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const html = buildLandingPage(telegramUrl);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              return new Response(html, {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    headers: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            "Content-Type": "text/html;charset=UTF-8",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    "Cache-Control": "no-cache"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  // ── Unknown route — redirect to channel ───────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return Response.redirect("https://t.me/Moviesss4ers", 302);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
